kernel void heartwall_kernel(
    params_common common,
    int* endoRow,
    int* endoCol,
    int* tEndoRowLoc,
    int* tEndoColLoc,
    int* epiRow,
    int* epiCol,
    int* tEpiRowLoc,
    int* tEpiColLoc,
    fp* d_frame,
    fp* d_endoT,
    fp* d_epiT,
    fp* d_in2,
    fp* d_in2_sqr,
    fp* d_in_mod,
    fp* d_in_sqr,
    fp* d_conv,
    fp* d_in2_pad,
    fp* d_in2_sub,
    fp* d_in2_sub2_sqr,
    fp* d_tMask,
    fp* d_mask_conv,
    int frame_no
)
{
    int point_no = get_global_id(0);

    if (point_no >= common.allPoints) return;

    int* d_Row;
    int* d_Col;
    int* d_tRowLoc;
    int* d_tColLoc;
    fp* d_T;
    int in_pointer;

    if (point_no < common.endoPoints) {
        d_Row = endoRow;
        d_Col = endoCol;
        d_tRowLoc = tEndoRowLoc;
        d_tColLoc = tEndoColLoc;
        d_T = d_endoT;
        in_pointer = point_no * common.in_elem;
    } else {
        int epi_point = point_no - common.endoPoints;
        d_Row = epiRow;
        d_Col = epiCol;
        d_tRowLoc = tEpiRowLoc;
        d_tColLoc = tEpiColLoc;
        d_T = d_epiT;
        in_pointer = epi_point * common.in_elem;
    }

    fp* d_in = &d_T[in_pointer];

    fp* private_d_in2 = &d_in2[point_no * common.in2_elem];
    fp* private_d_in2_sqr = &d_in2_sqr[point_no * common.in2_elem];
    fp* private_d_in_mod = &d_in_mod[point_no * common.in_mod_elem];
    fp* private_d_in_sqr = &d_in_sqr[point_no * common.in_mod_elem];
    fp* private_d_conv = &d_conv[point_no * common.conv_elem];
    fp* private_d_in2_pad = &d_in2_pad[point_no * common.in2_pad_elem];
    fp* private_d_in2_sub = &d_in2_sub[point_no * common.in2_sub_elem];
    fp* private_d_in2_sub2_sqr = &d_in2_sub2_sqr[point_no * common.in2_sub2_elem];
    fp* private_d_tMask = &d_tMask[point_no * common.tMask_elem];
    fp* private_d_mask_conv = &d_mask_conv[point_no * common.mask_conv_elem];

    int ei_new;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    fp s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    fp sum;
    int pos_ori;
    fp temp;
    fp temp2;
    int location;
    int cent;
    int tMask_row;
    int tMask_col;
    fp largest_value_current = 0;
    fp largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    fp fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    fp in_final_sum;
    fp in_sqr_final_sum;
    fp mean;
    fp mean_sqr;
    fp variance;
    fp deviation;
    fp denomT;
    int pointer;
    int ori_pointer;
    int loc_pointer;
    int ei_mod;

    if (frame_no == 0) {
        pointer = point_no * common.no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no];
        d_tColLoc[pointer] = d_Col[point_no];

        d_in = &d_T[in_pointer];

        for (col = 0; col < common.in_cols; col++) {
            for (row = 0; row < common.in_rows; row) {
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * common.frame_rows + ori_row;
                d_in[col * common.in_rows + row] = d_frame[ori_pointer];
            }
        }
    }

    if (frame_no != 0) {
        in2_rowlow = d_Row[point_no] - common.sSize;
        in2_collow = d_Col[point_no] - common.sSize;

        for (col = 0; col < common.in2_cols; col++) {
            for (row = 0; row < common.in2_rows; row++) {
                ori_row = row + in2_rowlow - 1;
                ori_col = col + in2_collow - 1;
                temp = d_frame[ori_col * common.frame_rows + ori_row];
                private_d_in2[col * common.in2_rows + row] = temp;
                private_d_in2_sqr[col * common.in2_rows + row] = temp * temp;
            }
        }

        d_in = &d_T[in_pointer];

        for (col = 0; col < common.in_cols; col++) {
            for (row = 0; row < common.in_rows; row++) {
                rot_row = (common.in_rows - 1) - row;
                rot_col = (common.in_rows - 1) - col;
                pointer = rot_col * common.in_rows + rot_row;
                temp = d_in[pointer];
                private_d_in_mod[col * common.in_rows + row] = temp;
                private_d_in_sqr[pointer] = temp * temp;
            }
        }

        in_final_sum = 0;
        for (i = 0; i < common.in_elem; i++) {
            in_final_sum = in_final_sum + d_in[i];
        }

        in_sqr_final_sum = 0;
        for (i = 0; i < common.in_elem; i++) {
            in_sqr_final_sum = in_sqr_final_sum + private_d_in_sqr[i];
        }

        mean = in_final_sum / common.in_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / common.in_elem) - mean_sqr;
        deviation = sqrt(variance);
        denomT = sqrt((fp)(common.in_elem - 1)) * deviation;

        for (col = 1; col <= common.conv_cols; col++) {
            j = col + common.joffset;
            jp1 = j + 1;
            if (common.in2_cols < jp1) {
                ja1 = jp1 - common.in2_cols;
            } else {
                ja1 = 1;
            }
            if (common.in_cols < j) {
                ja2 = common.in_cols;
            } else {
                ja2 = j;
            }

            for (row = 1; row <= common.conv_rows; row++) {
                i = row + common.ioffset;
                ip1 = i + 1;

                if (common.in2_rows < ip1) {
                    ia1 = ip1 - common.in2_rows;
                } else {
                    ia1 = 1;
                }
                if (common.in_rows < i) {
                    ia2 = common.in_rows;
                } else {
                    ia2 = i;
                }

                s = 0;

                for (ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for (ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s = s + private_d_in_mod[common.in_rows * (ja - 1) + ia - 1] * private_d_in2[common.in2_rows * (jb - 1) + ib - 1];
                    }
                }

                private_d_conv[(col - 1) * common.conv_rows + (row - 1)] = s;
            }
        }

        for (col = 0; col < common.in2_pad_cols; col++) {
            for (row = 0; row < common.in2_pad_rows; row++) {
                if (row > (common.in2_pad_add_rows - 1) &&
                    row < (common.in2_pad_add_rows + common.in2_rows) &&
                    col > (common.in2_pad_add_cols - 1) &&
                    col < (common.in2_pad_add_cols + common.in2_cols)) {
                    ori_row = row - common.in2_pad_add_rows;
                    ori_col = col - common.in2_pad_add_cols;
                    private_d_in2_pad[col * common.in2_pad_rows + row] = private_d_in2[ori_col * common.in2_rows + ori_row];
                } else {
                    private_d_in2_pad[col * common.in2_pad_rows + row] = 0;
                }
            }
        }

        for (ei_new = 0; ei_new < common.in2_pad_cols; ei_new++) {
            pos_ori = ei_new * common.in2_pad_rows;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_pad_rows; position = position + 1) {
                private_d_in2_pad[position] = private_d_in2_pad[position] + sum;
                sum = private_d_in2_pad[position];
            }
        }

        for (col = 0; col < common.in2_sub_cols; col++) {
            for (row = 0; row < common.in2_sub_rows; row++) {
                ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + common.in2_pad_cumv_sel_collow - 1;
                temp = private_d_in2_pad[ori_col * common.in2_pad_rows + ori_row];

                ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
                temp2 = private_d_in2_pad[ori_col * common.in2_pad_rows + ori_row];

                private_d_in2_sub[col * common.in2_sub_rows + row] = temp - temp2;
            }
        }

        for (ei_new = 0; ei_new < common.in2_sub_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_sub_elem; position = position + common.in2_sub_rows) {
                private_d_in2_sub[position] = private_d_in2_sub[position] + sum;
                sum = private_d_in2_sub[position];
            }
        }

        for (col = 0; col < common.in2_sub2_cols; col++) {
            for (row = 0; row < common.in2_sub2_rows; row++) {
                ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + common.in2_sub_cumh_sel_collow - 1;
                temp = private_d_in2_sub[ori_col * common.in2_sub_rows + ori_row];

                ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
                temp2 = private_d_in2_sub[ori_col * common.in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                private_d_in2_sub2_sqr[col * common.in2_sub2_rows + row] = temp2 * temp2;

                private_d_conv[col * common.in2_sub2_rows + row] = private_d_conv[col * common.in2_sub2_rows + row] - temp2 * in_final_sum / common.in_elem;
            }
        }

        for (col = 0; col < common.in2_pad_cols; col++) {
            for (row = 0; row < common.in2_pad_rows; row++) {
                if (row > (common.in2_pad_add_rows - 1) &&
                    row < (common.in2_pad_add_rows + common.in2_rows) &&
                    col > (common.in2_pad_add_cols - 1) &&
                    col < (common.in2_pad_add_cols + common.in2_cols)) {
                    ori_row = row - common.in2_pad_add_rows;
                    ori_col = col - common.in2_pad_add_cols;
                    private_d_in2_pad[col * common.in2_pad_rows + row] = private_d_in2_sqr[ori_col * common.in2_rows + ori_row];
                } else {
                    private_d_in2_pad[col * common.in2_pad_rows + row] = 0;
                }
            }
        }

        for (ei_new = 0; ei_new < common.in2_pad_cols; ei_new++) {
            pos_ori = ei_new * common.in2_pad_rows;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_pad_rows; position = position + 1) {
                private_d_in2_pad[position] = private_d_in2_pad[position] + sum;
                sum = private_d_in2_pad[position];
            }
        }

        for (col = 0; col < common.in2_sub_cols; col++) {
            for (row = 0; row < common.in2_sub_rows; row++) {
                ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + common.in2_pad_cumv_sel_collow - 1;
                temp = private_d_in2_pad[ori_col * common.in2_pad_rows + ori_row];

                ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
                temp2 = private_d_in2_pad[ori_col * common.in2_pad_rows + ori_row];

                private_d_in2_sub[col * common.in2_sub_rows + row] = temp - temp2;
            }
        }

        for (ei_new = 0; ei_new < common.in2_sub_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_sub_elem; position = position + common.in2_sub_rows) {
                private_d_in2_sub[position] = private_d_in2_sub[position] + sum;
                sum = private_d_in2_sub[position];
            }
        }

        for (col = 0; col < common.conv_cols; col++) {
            for (row = 0; row < common.conv_rows; row++) {
                ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + common.in2_sub_cumh_sel_collow - 1;
                temp = private_d_in2_sub[ori_col * common.in2_sub_rows + ori_row];

                ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
                temp2 = private_d_in2_sub[ori_col * common.in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                temp2 = temp2 - (private_d_in2_sub2_sqr[col * common.conv_rows + row] / common.in_elem);

                if (temp2 < 0) {
                    temp2 = 0;
                }
                temp2 = sqrt(temp2);

                temp2 = denomT * temp2;

                private_d_conv[col * common.conv_rows + row] = private_d_conv[col * common.conv_rows + row] / temp2;
            }
        }

        cent = common.sSize + common.tSize + 1;
        pointer = frame_no - 1 + point_no * common.no_frames;
        tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
        tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

        for (ei_new = 0; ei_new < common.tMask_elem; ei_new++) {
            private_d_tMask[ei_new] = 0;
        }
        private_d_tMask[tMask_col * common.tMask_rows + tMask_row] = 1;

        for (col = 1; col <= common.mask_conv_cols; col++) {
            j = col + common.mask_conv_joffset;
            jp1 = j + 1;
            if (common.mask_cols < jp1) {
                ja1 = jp1 - common.mask_cols;
            } else {
                ja1 = 1;
            }
            if (common.tMask_cols < j) {
                ja2 = common.tMask_cols;
            } else {
                ja2 = j;
            }

            for (row = 1; row <= common.mask_conv_rows; row++) {
                i = row + common.mask_conv_ioffset;
                ip1 = i + 1;

                if (common.mask_rows < ip1) {
                    ia1 = ip1 - common.mask_rows;
                } else {
                    ia1 = 1;
                }
                if (common.tMask_rows < i) {
                    ia2 = common.tMask_rows;
                } else {
                    ia2 = i;
                }

                s = 0;

                for (ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for (ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s = s + private_d_tMask[common.tMask_rows * (ja - 1) + ia - 1] * 1;
                    }
                }

                private_d_mask_conv[(col - 1) * common.conv_rows + (row - 1)] = private_d_conv[(col - 1) * common.conv_rows + (row - 1)] * s;
            }
        }

        fin_max_val = 0;
        fin_max_coo = 0;
        for (i = 0; i < common.mask_conv_elem; i++) {
            if (private_d_mask_conv[i] > fin_max_val) {
                fin_max_val = private_d_mask_conv[i];
                fin_max_coo = i;
            }
        }

        largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
        largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
        if ((fin_max_coo + 1) % common.mask_conv_rows == 0) {
            largest_row = common.mask_conv_rows - 1;
            largest_col = largest_col - 1;
        }

        largest_row = largest_row + 1;
        largest_col = largest_col + 1;
        offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
        offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
        pointer = point_no * common.no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
        d_tColLoc[pointer] = d_Col[point_no] + offset_col;
    }

    if (frame_no != 0 && (frame_no % 10 == 0)) {
        loc_pointer = point_no * common.no_frames + frame_no;
        d_Row[point_no] = d_tRowLoc[loc_pointer];
        d_Col[point_no] = d_tColLoc[loc_pointer];

        d_in = &d_T[in_pointer];

        for (col = 0; col < common.in_cols; col++) {
            for (row = 0; row < common.in_rows; row++) {
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * common.frame_rows + ori_row;
                d_in[col * common.in_rows + row] = common.alpha * d_in[col * common.in_rows + row] + (1.00 - common.alpha) * d_frame[ori_pointer];
            }
        }
    }
}
